INSERT INTO `parwas` (`id`, `name`, `slug`, `description`, `image`, `created_at`, `updated_at`) VALUES (1, 'Adi Parwa', 'adi-parwa', 'Kitab pertama yang menceritakan asal-usul nenek moyang Pandawa dan Korawa serta masa kecil mereka.', NULL, '2026-02-11 23:37:24', '2026-02-11 23:37:24');
